prefix_max = [a[0]]
for i in range(1, n):
    prefix_min.append(min(prefix_min[i-1], a[i]))
    prefix_max.append(max(prefix_max[i-1], a[i]))

def count_blocks(l, r):
    if l == 0:
        return prefix_max[r] - prefix_min[r] + 1
    else:
        return prefix_max[r] - prefix_max[l-1] - (prefix_min[r] - prefix_min[l-1]) + 1

ans = 0
